mapper.select:
select bs.id, bs.name, bs.phone, bs.email, bs.logo, bs.description, bs.category_id, bs.status, bs.updated_time, bs.last_login_time, ca.name categoryName, ba.province_id, ba.city_id, ba.district_id, (select round(avg(br.score), 1) from business_rating br where br.business_id = bs.id) ratting from business bs left join category ca on ca.id = bs.category_id left join business_address ba on ba.business_id = bs.id
and bs.name LIKE concat('%',#{pageDto.name},'%')
and bs.category_id = #{pageDto.categoryId}
and ba.province_id = #{pageDto.provinceId}
and ba.city_id = #{pageDto.cityId}
and ba.district_id = #{pageDto.districtId}
and bs.status = #{pageDto.status}
and (select round(avg(br.score), 1) from business_rating br where br.business_id = bs.id) >= #{pageDto.minRating}
and (select round(avg(br.score), 1) from business_rating br where br.business_id = bs.id) <= #{pageDto.maxRating}
order by ratting ${pageDto.ratingSort}
order by bs.updated_time desc

select bs.id, bs.name, bs.logo, bs.description, bs.category_id, ba.province_id, ba.city_id, ba.district_id, (select round(avg(br.score), 1) from business_rating br where br.business_id = bs.id) ratting from business bs left join category ca on ca.id = bs.category_id left join business_address ba on ba.business_id = bs.id
and bs.status IN (2, 6)
and bs.name LIKE concat('%',#{pageDto.name},'%')
and bs.category_id = #{pageDto.categoryId}
and ba.province_id = #{pageDto.provinceId}
and ba.city_id = #{pageDto.cityId}
and ba.district_id = #{pageDto.districtId}
